+    /* usual getopt loop */
+    while (-1 != (c = getopt(argc, argv, "b:i:m:tv"))) {
+      switch(c) {
+      case 'b':
+	BASE_ADDR = strtoul(optarg, NULL, 0);
+	break;
+      case 'i':
+	iface = optarg;
+	break;
+      case 'm':
+	media = atoi(optarg);
+	break;
+      case 't':
+	tflag++;
